#!/usr/bin/env bash
# ip.sh — 完本与 IP 改编变现（短剧时代重写的下游工作流） SOP walkthrough for 网文写作.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="网文写作"
WORKFLOW="完本与 IP 改编变现（短剧时代重写的下游工作流）"

usage() {
  cat <<EOF
ip.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./ip.sh             # interactive
  ./ip.sh --dry-run
  ./ip.sh --json
  ./ip.sh --explain
  ./ip.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "完本与 IP 改编变现（短剧时代重写的下游工作流）" 工作流。

一句话: 从「作品完本/数据达标」到「影视/微短剧/动漫/游戏/有声/漫画多形态授权变现」——2025 起**微短剧成为最快变现出口**，IP 改编工作流被「数据筛故事→短剧产能放大」的工业化模式重写。

入门 SOP 共 4 步, 失败模式自检 3 项。

相关心智模型:
  • 黄金三章定生死：为留人而非为铺垫写开局: 网文开局不是慢热铺垫，是前三章/万字内必须抛出金手指 + 制造冲突 + 埋钩子 + 建立代入，否则签约率与追读直接塌——「最惨/最爽不过三章」。
  • 爽点是可理性设计的工程对象，不是灵感: 愤怒的香蕉「一开始是欲望，到后来是情绪，最后变成需求」——爽点能被作者主动观察、拆解、设计，心理描写可把爽感挖到极致，而非等灵感降临。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**完本/达标**：作品完本或数据（订阅/完读/收藏）达 IP 评估阈值，进入平台 IP 池。 (evidence: [T03-S016])"
  "**平台数据筛选**：平台用阅读数据筛选可改编故事（番茄「流量+数据」工业化模式）。 (evidence: [T03-S014, T03-S016])"
  "**改编对接**：影视/短剧/动漫/游戏/有声/漫画方授权对接，短篇改编门槛低、周期短（《真千金她是学霸》上线到登顶短剧仅 64 天）。 (evidence: [T03-S014, T03-S015])"
  "**多形态分发**：唐三式全版权运营——一个 IP 跑动漫/游戏/影视/有声多线。 (evidence: [T03-S004])"
)
declare -a FAILURE_MODES=(
  "**太监/弃书断改编**：书太监=IP 价值归零、无改编 → 想变现就得完本或维持数据。"
  "**题材难改编**：纯设定流/文笔流难压缩成短剧，错过最快变现出口 → 想吃短剧红利就写可改编的成熟模式或短故事。"
  "**改编魔改原著**：影视/短剧改编偏离原著爽点，原著粉与新观众两头不讨好（天蚕土豆点出的玄幻改编通病） → 改编需保留核心爽点。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "ip-walkthrough"
fi
